import { useState, useMemo, useEffect, useCallback } from 'react';

// ─────────────────────────────────────────────────────────────────────────────
// EMPTY DATA SOURCE — All trade data is loaded from enriched_trades.json at runtime.
// The CSV is no longer hardcoded here; it is generated by the local pipeline
// (gmail → PDFs → pdf_parser → fetch_and_analyze) and gitignored as financial PII.
// If enriched_trades.json is missing, the dashboard renders an empty state.
// ─────────────────────────────────────────────────────────────────────────────
const RAW_CSV = `Trade #,Symbol,Side,Entry Time,Exit Time,Qty,Entry Price,Exit Price,P&L Points,P&L (₹),Duration`;

// ─────────────────────────────────────────────────────────────────────────────
// CSV PARSING — New pre-paired format
// Each row is already a complete round-trip trade
// ─────────────────────────────────────────────────────────────────────────────
function parseCSV(csv) {
  const lines = csv.trim().split('\n');
  return lines.slice(1).map(line => {
    const vals = line.split(',');
    const tradeNum = parseInt(vals[0]);
    const symbol = vals[1].trim();
    const side = vals[2].trim();           // LONG or SHORT
    const entryTimeStr = vals[3].trim();
    const exitTimeStr = vals[4].trim();
    const qty = parseInt(vals[5]);
    const entryPrice = parseFloat(vals[6]);
    const exitPrice = parseFloat(vals[7]);
    const pnlPoints = parseFloat(vals[8]);
    const pnlRupees = parseFloat(vals[9]);
    const durationStr = vals[10].trim();

    // Build the pair structure compatible with downstream analysis
    return {
      entry: {
        dateTime: new Date(entryTimeStr),
        dateTimeStr: entryTimeStr,
        symbol,
        side,              // LONG or SHORT
        qty,
        price: entryPrice,
      },
      exit: {
        dateTime: new Date(exitTimeStr),
        dateTimeStr: exitTimeStr,
        symbol,
        side: side === 'LONG' ? 'SHORT' : 'LONG', // exit is opposite
        qty,
        price: exitPrice,
      },
      tradeNum,
      pnlPoints,
      pnlRupees,
      durationStr,
    };
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// TRADE METRICS — Uses pre-calculated P&L from CSV + computes MFE/MAE
// ─────────────────────────────────────────────────────────────────────────────
function computeMetrics(pair, allPairsForDay) {
  const { entry, exit, pnlPoints, pnlRupees, durationStr: csvDuration } = pair;
  const isLong = entry.side === 'LONG';
  const pnl = pnlRupees;
  const pnlPct = (pnlPoints / entry.price) * 100;
  const durationMs = exit.dateTime - entry.dateTime;
  const durationMin = Math.round(durationMs / 60000);

  // MFE / MAE — estimate from intraday peers on the same day/symbol
  const dayPeers = allPairsForDay.filter(p =>
    p.entry.symbol === entry.symbol
  );
  const allPrices = dayPeers.flatMap(p => [p.entry.price, p.exit.price]);
  const maxPrice = Math.max(...allPrices, entry.price, exit.price);
  const minPrice = Math.min(...allPrices, entry.price, exit.price);

  let mfePoints, maePoints;
  if (isLong) {
    mfePoints = maxPrice - entry.price;
    maePoints = entry.price - minPrice;
  } else {
    mfePoints = entry.price - minPrice;
    maePoints = maxPrice - entry.price;
  }
  const mfe = (mfePoints / entry.price) * 100;
  const mae = (maePoints / entry.price) * 100;

  return { pnl, pnlPct, duration: durationMin, durationStr: csvDuration, mfe, mae, mfePoints, maePoints };
}

// ─────────────────────────────────────────────────────────────────────────────
// PATTERN DETECTION
// ─────────────────────────────────────────────────────────────────────────────

// IST conversion helper (UTC+5:30) — the CSV appears to be IST
function toIST(d) { return new Date(d.getTime()); } // already in IST from CSV

function getHourIST(d) { return d.getHours(); }
function getMinIST(d) { return d.getMinutes(); }

// 11:00-11:30 PST = 00:30-01:00 IST next day... but user said PST.
// Since the market data is Indian (BankNifty/Nifty), let's map to IST equivalent.
// 11:00 PST = 00:30 IST (next day). That doesn't match market hours.
// More likely: user means 11:00-11:30 AM *local market time* (IST).
// The "Stop Run" concept in Indian markets maps to ~11:00-11:30 IST = mid-morning.
function isStopRunWindow(d) {
  const h = getHourIST(d);
  const m = getMinIST(d);
  return h === 11 && m >= 0 && m <= 30;
}

// Middle of the Middle: midday (12:00-13:30 IST) in a mid-range
function isMiddleOfMiddle(d, allDayPrices) {
  const h = getHourIST(d);
  if (h < 12 || h > 13) return false;
  if (h === 13 && getMinIST(d) > 30) return false;
  // mid-range: entry price is within 40-60% of day's range
  if (allDayPrices.length < 2) return true;
  const hi = Math.max(...allDayPrices);
  const lo = Math.min(...allDayPrices);
  const range = hi - lo;
  return range > 0; // midday is always suspect in Brooks
}

// Barb Wire: 3+ overlapping trades in narrow range with small movements
function detectBarbWire(pair, dayPeers) {
  const entryTime = pair.entry.dateTime.getTime();
  // Look at nearby trades within ±30min
  const nearby = dayPeers.filter(p => {
    const t = p.entry.dateTime.getTime();
    return Math.abs(t - entryTime) < 30 * 60000;
  });
  if (nearby.length < 3) return false;
  // Check for overlapping ranges and small movements
  const ranges = nearby.map(p => ({
    hi: Math.max(p.entry.price, p.exit.price),
    lo: Math.min(p.entry.price, p.exit.price),
  }));
  // All ranges overlap?
  const overlapHi = Math.min(...ranges.map(r => r.hi));
  const overlapLo = Math.max(...ranges.map(r => r.lo));
  if (overlapHi <= overlapLo) return false;
  // Check if any trade is a doji (very small body relative to the instrument)
  const threshold = pair.entry.price * 0.0005; // 0.05% = doji threshold
  const hasDoji = nearby.some(p => Math.abs(p.exit.price - p.entry.price) < threshold);
  return hasDoji;
}

// 2HM: time away from EMA proxy. Since we don't have full candle data, estimate.
// We look at trades on the same day and compute a running average.
function compute2HM(pair, dayPeers) {
  const prices = dayPeers
    .filter(p => p.entry.dateTime <= pair.entry.dateTime)
    .flatMap(p => [p.entry.price, p.exit.price]);
  if (prices.length === 0) return 0;
  const ema = prices.reduce((a, b) => a + b, 0) / prices.length;
  const distFromEma = Math.abs(pair.entry.price - ema);
  const distPct = (distFromEma / ema) * 100;
  // Map to minutes: higher distance = longer time away
  return Math.min(150, Math.round(distPct * 200));
}

// Gap Bar: First trade after a significant gap from prior session
function isGapBar(pair, allPairs, idx) {
  if (idx === 0) return false;
  const prevPair = allPairs[idx - 1];
  const prevDay = prevPair.entry.dateTimeStr.split(' ')[0];
  const curDay = pair.entry.dateTimeStr.split(' ')[0];
  if (prevDay === curDay) return false;
  // Different day — check if first trade of the day for the symbol
  const isFirst = !allPairs.slice(0, idx).some(p =>
    p.entry.dateTimeStr.split(' ')[0] === curDay && p.entry.symbol === pair.entry.symbol
  );
  if (!isFirst) return false;
  const gap = Math.abs(pair.entry.price - prevPair.exit.price);
  const gapPct = (gap / prevPair.exit.price) * 100;
  return gapPct > 0.3; // >0.3% gap
}

// Shaved Bar: entry price near the extreme of the trade range
function isShavedBar(pair) {
  const hi = Math.max(pair.entry.price, pair.exit.price);
  const lo = Math.min(pair.entry.price, pair.exit.price);
  const range = hi - lo;
  if (range === 0) return false;
  const isLong = pair.entry.side === 'LONG';
  // For longs: entry should be near the low (shaved bottom); For shorts: entry near the high
  if (isLong) return (pair.entry.price - lo) / range < 0.1;
  return (hi - pair.entry.price) / range < 0.1;
}

// Leg counting: sequential same-direction trades
function countLegs(pair, dayPeers) {
  const sameSide = dayPeers.filter(p =>
    p.entry.symbol === pair.entry.symbol &&
    p.entry.side === pair.entry.side &&
    p.entry.dateTime <= pair.entry.dateTime
  );
  return sameSide.length;
}

// Detect failed failure (trap): a loss immediately followed by a winning trade in opposite direction
function isFailedFailure(pair, allPairs, idx) {
  if (idx === 0) return false;
  const prev = allPairs[idx - 1];
  if (prev.entry.symbol !== pair.entry.symbol) return false;
  const prevDay = prev.entry.dateTimeStr.split(' ')[0];
  const curDay = pair.entry.dateTimeStr.split(' ')[0];
  if (prevDay !== curDay) return false;
  const prevIsLong = prev.entry.side === 'LONG';
  const prevPnl = prev.pnlPoints;
  const curIsLong = pair.entry.side === 'LONG';
  const curPnl = pair.pnlPoints;
  // Previous trade lost and current is opposite direction and wins
  return prevPnl < 0 && curPnl > 0 && prevIsLong !== curIsLong;
}

// Institutional trap: entry where weak-hand stops would be
function isInstitutionalTrap(pair, dayPeers) {
  const prices = dayPeers.flatMap(p => [p.entry.price, p.exit.price]);
  if (prices.length < 4) return false;
  const hi = Math.max(...prices);
  const lo = Math.min(...prices);
  const range = hi - lo;
  if (range === 0) return false;
  const isLong = pair.entry.side === 'LONG';
  // Long entries near the low (stop-hunt zone) or short entries near the high
  if (isLong) return (pair.entry.price - lo) / range < 0.2;
  return (hi - pair.entry.price) / range < 0.2;
}

// ─────────────────────────────────────────────────────────────────────────────
// BROOKS SCORECARD (1-10)
// ─────────────────────────────────────────────────────────────────────────────
function computeBrooksScore(pair, dayPeers, allPairs, idx) {
  let context = 5;
  let setupReliability = 5;
  let signalBar = 5;
  let institutional = 5;

  const isLong = pair.entry.side === 'LONG';
  const pnl = pair.pnlPoints;
  const allDayPrices = dayPeers.flatMap(p => [p.entry.price, p.exit.price]);

  // Context (30%)
  const twoHM = compute2HM(pair, dayPeers);
  if (twoHM > 100) context += 3; // price away from EMA for 2+ hours equivalent
  // With-Trend bonus: if PnL > 0, assume with-trend
  if (pnl > 0) context += 2;
  // Middle of Middle penalty
  if (isMiddleOfMiddle(pair.entry.dateTime, allDayPrices)) context -= 4;
  // Stop run window bonus
  if (isStopRunWindow(pair.entry.dateTime)) context += 2;

  // Setup Reliability (30%)
  const leg = countLegs(pair, dayPeers);
  if (leg === 2) setupReliability += 3; // Second entry = high reliability
  if (leg === 1) setupReliability += 1; // First entry = moderate
  if (leg >= 3) setupReliability -= 2; // Overextended
  if (isFailedFailure(pair, allPairs, idx)) setupReliability += 2; // Failed final flag / breakout pullback

  // Signal Bar Quality (20%)
  const bodySize = Math.abs(pair.exit.price - pair.entry.price);
  const bodyPct = (bodySize / pair.entry.price) * 100;
  if (bodyPct > 0.1) signalBar += 2; // Strong trend body
  if (isShavedBar(pair)) signalBar += 2; // Shaved extremes
  if (detectBarbWire(pair, dayPeers)) signalBar -= 3; // Doji in barb wire
  if (bodyPct < 0.02) signalBar -= 2; // Doji-like

  // Institutional Logic (20%)
  if (isInstitutionalTrap(pair, dayPeers)) institutional += 2;
  if (isFailedFailure(pair, allPairs, idx)) institutional += 2;

  // Clamp all to 1-10
  const clamp = v => Math.max(1, Math.min(10, Math.round(v)));
  context = clamp(context);
  setupReliability = clamp(setupReliability);
  signalBar = clamp(signalBar);
  institutional = clamp(institutional);

  const total = Math.round(context * 0.3 + setupReliability * 0.3 + signalBar * 0.2 + institutional * 0.2);

  return { total: clamp(total), context, setupReliability, signalBar, institutional };
}

