function generateAnalogy(pair, flags) {
  if (flags.isFailedFailure) return ANALOGIES.failedFailure[Math.floor(Math.random() * 2)];
  if (flags.isBarbWire) return ANALOGIES.barbWire[Math.floor(Math.random() * 2)];
  if (flags.isMiddleOfMiddle) return ANALOGIES.middleMiddle[Math.floor(Math.random() * 2)];
  if (flags.leg === 2) return ANALOGIES.secondEntry[Math.floor(Math.random() * 2)];
  if (flags.isStopRun) return ANALOGIES.stopRun[Math.floor(Math.random() * 2)];
  if (flags.leg >= 3) return ANALOGIES.overextended[Math.floor(Math.random() * 2)];
  if (flags.isShavedBar) return ANALOGIES.shavedBar[Math.floor(Math.random() * 2)];
  if (flags.isGapBar) return ANALOGIES.gapBar[Math.floor(Math.random() * 2)];
  if (flags.pnl > 0) return ANALOGIES.withTrend[Math.floor(Math.random() * 2)];
  return ANALOGIES.generic[Math.floor(Math.random() * 2)];
}

// ─────────────────────────────────────────────────────────────────────────────
// MAIN ANALYSIS ENGINE
// ─────────────────────────────────────────────────────────────────────────────
function analyzeAllTrades() {
  const allPairs = parseCSV(RAW_CSV);

  // Sort by entry time for consistent ordering
  allPairs.sort((a, b) => a.entry.dateTime - b.entry.dateTime);

  // Group by day for day-level analysis
  const byDay = {};
  allPairs.forEach(p => {
    const day = p.entry.dateTimeStr.split(' ')[0];
    if (!byDay[day]) byDay[day] = [];
    byDay[day].push(p);
  });

  return allPairs.map((pair, idx) => {
    const day = pair.entry.dateTimeStr.split(' ')[0];
    const dayPeers = byDay[day] || [];
    const metrics = computeMetrics(pair, dayPeers);
    const score = computeBrooksScore(pair, dayPeers, allPairs, idx);
    const isBW = detectBarbWire(pair, dayPeers);
    const twoHM = compute2HM(pair, dayPeers);
    const shaved = isShavedBar(pair);
    const gap = isGapBar(pair, allPairs, idx);
    const leg = countLegs(pair, dayPeers);
    const ff = isFailedFailure(pair, allPairs, idx);
    const trap = isInstitutionalTrap(pair, dayPeers);
    const stopRun = isStopRunWindow(pair.entry.dateTime);
    const mom = isMiddleOfMiddle(pair.entry.dateTime,
      dayPeers.flatMap(p => [p.entry.price, p.exit.price])
    );

    // Measured move: estimate target as 2x the first pullback
    const pullback = Math.abs(pair.exit.price - pair.entry.price);
    const measuredMoveTarget = pullback * 2;
    const reachedMM = metrics.mfePoints >= measuredMoveTarget && measuredMoveTarget > 0;

    const flags = {
      isBarbWire: isBW, twoHM, isShavedBar: shaved, isGapBar: gap,
      leg, isFailedFailure: ff, isInstitutionalTrap: trap,
      isStopRun: stopRun, isMiddleOfMiddle: mom, pnl: metrics.pnl,
      reachedMM, measuredMoveTarget, pullback,
    };

    const analogy = generateAnalogy(pair, flags);

    return { pair, metrics, score, flags, analogy, idx };
  });
}

