// Tooltip — pure CSS hover tooltip, no deps
function Tip({ text, children, pos = 'top' }) {
  if (!text) return children;
  const posClass = pos === 'bottom'
    ? 'top-full mt-2'
    : pos === 'left'
      ? 'right-full mr-2 top-1/2 -translate-y-1/2'
      : pos === 'right'
        ? 'left-full ml-2 top-1/2 -translate-y-1/2'
        : 'bottom-full mb-2';
  const centerX = pos === 'top' || pos === 'bottom' ? 'left-1/2 -translate-x-1/2' : '';
  return (
    <span className="relative group/tip inline-flex">
      {children}
      <span className={`absolute z-[100] ${posClass} ${centerX} px-3 py-1.5 rounded-lg bg-slate-800 border border-slate-600/80 text-[11px] text-slate-200 leading-snug max-w-[260px] whitespace-normal opacity-0 group-hover/tip:opacity-100 transition-opacity duration-200 pointer-events-none shadow-xl shadow-black/40`}>
        {text}
      </span>
    </span>
  );
}

