// ─────────────────────────────────────────────────────────────────────────────
// TRADE DETAIL MODAL — Full-session candlestick chart + Brooks annotations
// ─────────────────────────────────────────────────────────────────────────────

function BarByBarReplay({ totalBars, replayIdx, setReplayIdx, session }) {
  const [playing, setPlaying] = useState(false);

  useEffect(() => {
    if (!playing) return;
    const id = setInterval(() => {
      setReplayIdx(prev => {
        if (prev >= totalBars - 1) { setPlaying(false); return totalBars - 1; }
        return prev + 1;
      });
    }, 500);
    return () => clearInterval(id);
  }, [playing, totalBars, setReplayIdx]);

  useEffect(() => {
    const handler = (e) => {
      if (e.code === 'Space' && e.target.tagName !== 'INPUT') {
        e.preventDefault();
        setPlaying(p => !p);
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);

  const candle = session?.candles?.[replayIdx];
  const emaVal = session?.ema?.[replayIdx];

  return (
    <div className="flex items-center gap-3 px-4 py-2 bg-slate-800/50 rounded-lg border border-slate-700/30">
      <button
        onClick={() => setPlaying(p => !p)}
        className="w-8 h-8 flex items-center justify-center rounded-lg bg-slate-700 hover:bg-slate-600 text-white text-sm transition-colors flex-shrink-0"
      >
        {playing ? '⏸' : '▶'}
      </button>
      <input
        type="range"
        min={0}
        max={totalBars - 1}
        value={replayIdx}
        onChange={e => { setReplayIdx(parseInt(e.target.value)); setPlaying(false); }}
        className="flex-1 h-1.5 accent-blue-500"
      />
      <div className="flex items-center gap-3 text-xs font-mono text-slate-400 min-w-[220px] flex-shrink-0">
        <span>Bar {replayIdx + 1}/{totalBars}</span>
        {candle && <span className="text-slate-300">{candle.t}</span>}
        {emaVal != null && <span>EMA: <span className="text-amber-400">{emaVal.toFixed(1)}</span></span>}
      </div>
    </div>
  );
}

function SessionCandlestickChart({ session, trade, replayIdx, showAnnotations }) {
  const chartData = useMemo(() => {
    if (!session?.candles?.length) return null;
    const candles = session.candles;
    const ema = session.ema || [];
    const numBars = candles.length;
    const CW = 12;
    const PAD = { top: 20, bottom: 30, left: 65, right: 40 };
    const H = 400;
    const W = PAD.left + numBars * CW + PAD.right;

    const allPrices = candles.flatMap(c => [c.h, c.l]);
    if (session.priorDayHigh > 0) allPrices.push(session.priorDayHigh);
    if (session.priorDayLow > 0) allPrices.push(session.priorDayLow);

    const pMin = Math.min(...allPrices);
    const pMax = Math.max(...allPrices);
    const pRange = pMax - pMin || 1;
    const pad = pRange * 0.05;
    const yMin = pMin - pad;
    const yMax = pMax + pad;
    const yRange = yMax - yMin;

    const toY = (p) => PAD.top + (1 - (p - yMin) / yRange) * (H - PAD.top - PAD.bottom);
    const toX = (i) => PAD.left + i * CW + CW / 2;

    return { candles, ema, numBars, CW, PAD, H, W, yMin, yMax, yRange, toY, toX };
  }, [session]);

  if (!chartData) return <div className="text-slate-500 text-center py-10">No session data available</div>;

  const { candles, ema, numBars, CW, PAD, H, W, toY, toX, yMin, yRange } = chartData;
  const maxVisible = replayIdx != null ? replayIdx + 1 : numBars;

  const isLong = trade.pair?.entry?.side === 'LONG';
  const isWin = trade.metrics?.pnl > 0;
  const entryIdx = trade.entryIdx;
  const exitIdx = trade.exitIdx;
  const entryPrice = trade.pair?.entry?.price;
  const exitPrice = trade.pair?.exit?.price;

  const mfePrice = entryPrice != null ? (isLong ? entryPrice + (trade.metrics?.mfePoints || 0) : entryPrice - (trade.metrics?.mfePoints || 0)) : null;
  const maePrice = entryPrice != null ? (isLong ? entryPrice - (trade.metrics?.maePoints || 0) : entryPrice + (trade.metrics?.maePoints || 0)) : null;

  const mmTarget = trade.flags?.measuredMoveTarget;
  const mmPrice = mmTarget && entryPrice != null ? (isLong ? entryPrice + mmTarget : entryPrice - mmTarget) : null;

  const gridCount = 6;
  const gridLines = Array.from({ length: gridCount + 1 }, (_, i) => yMin + (yRange * i / gridCount));

  const timeLabels = [];
  for (let i = 0; i < candles.length; i += 6) timeLabels.push({ idx: i, t: candles[i].t });

  const emaPath = ema.slice(0, maxVisible).map((v, i) => `${i === 0 ? 'M' : 'L'}${toX(i).toFixed(1)},${toY(v).toFixed(1)}`).join(' ');

  const ctxStart = entryIdx != null ? Math.max(0, entryIdx - 20) : 0;
  const ctxEnd = entryIdx || 0;

  return (
    <svg viewBox={`0 0 ${W} ${H}`} className="w-full" style={{ maxHeight: '420px' }}>
      <rect width={W} height={H} fill="#0d1117" />

      {gridLines.map((p, i) => (
        <g key={i}>
          <line x1={PAD.left} y1={toY(p)} x2={W - PAD.right} y2={toY(p)} stroke="#1e293b" strokeWidth="0.5" />
          <text x={PAD.left - 5} y={toY(p) + 3} textAnchor="end" fill="#475569" fontSize="8" fontFamily="monospace">{p.toFixed(0)}</text>
        </g>
      ))}

      {timeLabels.map(({ idx, t }) => (
        <text key={idx} x={toX(idx)} y={H - 5} textAnchor="middle" fill="#475569" fontSize="7" fontFamily="monospace">{t}</text>
      ))}

      {showAnnotations && session.marketPhaseRegions?.map((r, i) => {
        const colors = { SPIKE: 'rgba(34,197,94,0.06)', CHANNEL: 'rgba(59,130,246,0.06)', TRADING_RANGE: 'rgba(148,163,184,0.03)' };
        return (
          <rect key={`phase-${i}`}
            x={toX(r.startIdx) - CW / 2} y={PAD.top}
            width={(r.endIdx - r.startIdx + 1) * CW}
            height={H - PAD.top - PAD.bottom}
            fill={colors[r.phase] || 'transparent'}
          />
        );
      })}

      {showAnnotations && session.barbWireZones?.map((z, i) => (
        <rect key={`bw-${i}`}
          x={toX(z.startIdx) - CW / 2} y={PAD.top}
          width={(z.endIdx - z.startIdx + 1) * CW}
          height={H - PAD.top - PAD.bottom}
          fill="rgba(148,163,184,0.08)" stroke="#64748b" strokeWidth="0.5" strokeDasharray="3,3"
        />
      ))}

      {entryIdx != null && (
        <rect
          x={toX(ctxStart) - CW / 2} y={PAD.top}
          width={(ctxEnd - ctxStart) * CW}
          height={H - PAD.top - PAD.bottom}
          fill="rgba(59,130,246,0.04)"
        />
      )}

      {entryIdx != null && exitIdx != null && exitIdx < maxVisible && (
        <rect
          x={toX(entryIdx) - CW / 2} y={PAD.top}
          width={(exitIdx - entryIdx + 1) * CW}
          height={H - PAD.top - PAD.bottom}
          fill={isWin ? 'rgba(34,197,94,0.07)' : 'rgba(239,68,68,0.07)'}
          stroke={isWin ? 'rgba(34,197,94,0.2)' : 'rgba(239,68,68,0.2)'}
          strokeWidth="0.5"
        />
      )}

      {session.priorDayHigh > 0 && (
        <g>
          <line x1={PAD.left} y1={toY(session.priorDayHigh)} x2={W - PAD.right} y2={toY(session.priorDayHigh)} stroke="#6b7280" strokeWidth="0.7" strokeDasharray="4,4" />
          <text x={W - PAD.right + 3} y={toY(session.priorDayHigh) + 3} fill="#6b7280" fontSize="7" fontFamily="monospace">PDH</text>
        </g>
      )}
      {session.priorDayLow > 0 && (
        <g>
          <line x1={PAD.left} y1={toY(session.priorDayLow)} x2={W - PAD.right} y2={toY(session.priorDayLow)} stroke="#6b7280" strokeWidth="0.7" strokeDasharray="4,4" />
          <text x={W - PAD.right + 3} y={toY(session.priorDayLow) + 3} fill="#6b7280" fontSize="7" fontFamily="monospace">PDL</text>
        </g>
      )}

      {mfePrice != null && (
        <g>
          <line x1={PAD.left} y1={toY(mfePrice)} x2={W - PAD.right} y2={toY(mfePrice)} stroke="#22c55e" strokeWidth="0.7" strokeDasharray="3,3" opacity="0.5" />
          <text x={W - PAD.right + 3} y={toY(mfePrice) + 3} fill="#22c55e" fontSize="7" fontFamily="monospace">MFE</text>
        </g>
      )}
      {maePrice != null && (
        <g>
          <line x1={PAD.left} y1={toY(maePrice)} x2={W - PAD.right} y2={toY(maePrice)} stroke="#ef4444" strokeWidth="0.7" strokeDasharray="3,3" opacity="0.5" />
          <text x={W - PAD.right + 3} y={toY(maePrice) + 3} fill="#ef4444" fontSize="7" fontFamily="monospace">MAE</text>
        </g>
      )}
      {mmPrice != null && (
        <g>
          <line x1={PAD.left} y1={toY(mmPrice)} x2={W - PAD.right} y2={toY(mmPrice)} stroke="#a855f7" strokeWidth="0.7" strokeDasharray="2,4" opacity="0.5" />
          <text x={W - PAD.right + 3} y={toY(mmPrice) + 3} fill="#a855f7" fontSize="7" fontFamily="monospace">MM</text>
        </g>
      )}

      {candles.slice(0, maxVisible).map((c, i) => {
        const x = toX(i);
        const isGreen = c.c > c.o;
        const bodyTop = toY(Math.max(c.o, c.c));
        const bodyBot = toY(Math.min(c.o, c.c));
        const bodyH = Math.max(bodyBot - bodyTop, 1);
        const bodyW = CW * 0.65;
        return (
          <g key={i}>
            <line x1={x} y1={toY(c.h)} x2={x} y2={toY(c.l)} stroke={isGreen ? '#22c55e' : '#ef4444'} strokeWidth="1" />
            <rect x={x - bodyW / 2} y={bodyTop} width={bodyW} height={bodyH} fill={isGreen ? '#22c55e' : '#ef4444'} rx="0.5" />
          </g>
        );
      })}

      {emaPath && <path d={emaPath} fill="none" stroke="#f59e0b" strokeWidth="1.2" opacity="0.8" />}

      {showAnnotations && session.trendlines?.map((tl, i) => (
        <line key={`tl-${i}`}
          x1={toX(tl.startIdx)} y1={toY(tl.startPrice)}
          x2={toX(Math.min(tl.endIdx, maxVisible - 1))} y2={toY(tl.endPrice)}
          stroke={tl.type === 'bull' ? '#22c55e' : '#ef4444'}
          strokeWidth="1.2"
          strokeDasharray={tl.broken ? '4,3' : 'none'}
          opacity="0.7"
        />
      ))}

      {showAnnotations && session.swingPoints?.filter(sp => sp.idx < maxVisible).map((sp, i) => (
        <text key={`sp-${i}`}
          x={toX(sp.idx)}
          y={sp.type === 'high' ? toY(sp.price) - 8 : toY(sp.price) + 12}
          textAnchor="middle"
          fill={sp.type === 'high' ? '#f59e0b' : '#60a5fa'}
          fontSize="10"
        >
          {sp.type === 'high' ? '△' : '▽'}
        </text>
      ))}

      {entryIdx != null && entryIdx < maxVisible && entryPrice != null && (
        <g>
          <line x1={toX(entryIdx)} y1={PAD.top} x2={toX(entryIdx)} y2={H - PAD.bottom} stroke="#3b82f6" strokeWidth="1" strokeDasharray="2,2" opacity="0.4" />
          <polygon
            points={`${toX(entryIdx)},${toY(entryPrice) - 6} ${toX(entryIdx) - 5},${toY(entryPrice) - 14} ${toX(entryIdx) + 5},${toY(entryPrice) - 14}`}
            fill="#3b82f6"
          />
          <text x={toX(entryIdx)} y={toY(entryPrice) - 17} textAnchor="middle" fill="#3b82f6" fontSize="7" fontWeight="bold">ENTRY</text>
        </g>
      )}

      {exitIdx != null && exitIdx < maxVisible && exitPrice != null && (
        <g>
          <line x1={toX(exitIdx)} y1={PAD.top} x2={toX(exitIdx)} y2={H - PAD.bottom} stroke={isWin ? '#22c55e' : '#ef4444'} strokeWidth="1" strokeDasharray="2,2" opacity="0.4" />
          <polygon
            points={`${toX(exitIdx)},${toY(exitPrice) + 6} ${toX(exitIdx) - 5},${toY(exitPrice) + 14} ${toX(exitIdx) + 5},${toY(exitPrice) + 14}`}
            fill={isWin ? '#22c55e' : '#ef4444'}
          />
          <text x={toX(exitIdx)} y={toY(exitPrice) + 25} textAnchor="middle" fill={isWin ? '#22c55e' : '#ef4444'} fontSize="7" fontWeight="bold">EXIT</text>
        </g>
      )}
    </svg>
  );
}

function ScoreDecompositionPanel({ trade }) {
  const decomp = trade.scoreDecomposition;
  const quality = trade.tradeQuality;

  const qualityBadges = {
    GOOD_WIN:  { icon: '🏆', label: 'Good Win',  cls: 'bg-emerald-500/15 text-emerald-400 border-emerald-500/30' },
    GOOD_LOSS: { icon: '✅', label: 'Good Loss', cls: 'bg-blue-500/15 text-blue-400 border-blue-500/30' },
    BAD_WIN:   { icon: '⚠️', label: 'Bad Win',   cls: 'bg-amber-500/15 text-amber-400 border-amber-500/30' },
    BAD_LOSS:  { icon: '❌', label: 'Bad Loss',  cls: 'bg-red-500/15 text-red-400 border-red-500/30' },
  };

  const phaseColors = {
    SPIKE: 'bg-emerald-500/15 text-emerald-300 border-emerald-500/30',
    CHANNEL: 'bg-blue-500/15 text-blue-400 border-blue-500/30',
    TRADING_RANGE: 'bg-slate-600/20 text-slate-400 border-slate-500/30',
  };

  const aisDisplay = {
    LONG:    { label: 'AIS: LONG ▲',    cls: 'text-emerald-400' },
    SHORT:   { label: 'AIS: SHORT ▼',   cls: 'text-red-400' },
    NEUTRAL: { label: 'AIS: NEUTRAL ─', cls: 'text-slate-400' },
  };

  const statusIcon = (score) => score >= 7 ? '✅' : score >= 4 ? '⚠️' : '❌';

  const components = [
    { key: 'context', label: 'Context', tip: TIPS.ctx },
    { key: 'setupReliability', label: 'Setup', tip: TIPS.set },
    { key: 'signalBar', label: 'Signal Bar', tip: TIPS.sig },
    { key: 'institutional', label: 'Institutional', tip: TIPS.inst },
    { key: 'pressure', label: 'Pressure', tip: TIPS.pres },
  ];

  const mfePct = trade.metrics?.mfe || 0;
  const maePct = trade.metrics?.mae || 0;
  const maxPct = Math.max(mfePct, maePct, 0.001);
  const phase = trade.flags?.marketPhase || 'TRADING_RANGE';
  const ais = trade.flags?.alwaysInStatus || 'NEUTRAL';
  const qb = qualityBadges[quality] || qualityBadges.BAD_LOSS;

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-3 flex-wrap">
        <Tip text={TIPS.marketPhase[phase]}>
          <span className={`px-3 py-1.5 rounded-lg border text-sm font-bold ${phaseColors[phase] || phaseColors.TRADING_RANGE}`}>
            {phase.replace('_', ' ')}
          </span>
        </Tip>
        <Tip text={TIPS.ais}>
          <span className={`text-sm font-mono font-bold ${aisDisplay[ais]?.cls || 'text-slate-400'}`}>
            {aisDisplay[ais]?.label || 'AIS: —'}
          </span>
        </Tip>
        {quality && (
          <Tip text={TIPS[quality === 'GOOD_WIN' ? 'goodWin' : quality === 'GOOD_LOSS' ? 'goodLoss' : quality === 'BAD_WIN' ? 'badWin' : 'badLoss']}>
            <span className={`px-3 py-1.5 rounded-lg border text-sm font-bold ${qb.cls}`}>
              {qb.icon} {qb.label}
            </span>
          </Tip>
        )}
        {trade.mistakeTag && (
          <Tip text={TIPS[trade.mistakeTag === '#FOMO' ? 'fomo' : trade.mistakeTag === '#LOW_CONTEXT' ? 'lowContext' : trade.mistakeTag === '#BARB_WIRE' ? 'barbWireTag' : trade.mistakeTag === '#REVENGE' ? 'revenge' : trade.mistakeTag === '#OVEREXTENDED' ? 'overextended' : trade.mistakeTag === '#GOOD_ENTRY' ? 'goodEntry' : 'perfectStorm']}>
            <span className="px-2 py-1 rounded-full text-[10px] font-bold bg-red-500/10 text-red-400 border border-red-500/20">
              {trade.mistakeTag}
            </span>
          </Tip>
        )}
      </div>

      {/* Institutional Structure Indicators */}
      <div className="flex flex-wrap gap-1.5">
        {trade.flags?.isTFO && (
          <Tip text={TIPS.tfoDetail}>
            <span className="px-2 py-1 rounded-lg text-[10px] font-bold bg-amber-500/15 text-amber-300 border border-amber-500/25">
              🌅 TFO {trade.flags.tfoDirection}
            </span>
          </Tip>
        )}
        {trade.flags?.isM2B && (
          <Tip text={TIPS.m2b}>
            <span className="px-2 py-1 rounded-lg text-[10px] font-bold bg-emerald-500/15 text-emerald-300 border border-emerald-500/25">
              📐 M2B — 2-leg pullback to EMA
            </span>
          </Tip>
        )}
        {trade.flags?.isM2S && (
          <Tip text={TIPS.m2s}>
            <span className="px-2 py-1 rounded-lg text-[10px] font-bold bg-red-500/15 text-red-300 border border-red-500/25">
              📐 M2S — 2-leg rally to EMA
            </span>
          </Tip>
        )}
        {trade.flags?.channelLineBreak && (
          <Tip text={TIPS.channelOvershoot}>
            <span className="px-2 py-1 rounded-lg text-[10px] font-bold bg-violet-500/15 text-violet-300 border border-violet-500/25">
              💥 Channel {trade.flags.channelLineBreak === 'BULL_OVERSHOOT' ? '▲' : '▼'} Overshoot — Climactic Trap
            </span>
          </Tip>
        )}
        {trade.flags?.testOfExtreme && (
          <Tip text={TIPS.testOfExtreme}>
            <span className={`px-2 py-1 rounded-lg text-[10px] font-bold border ${
              trade.flags.testOfExtreme.includes('OVERSHOOT')
                ? 'bg-cyan-500/15 text-cyan-300 border-cyan-500/25'
                : 'bg-slate-600/15 text-slate-400 border-slate-500/25'
            }`}>
              🔬 Test: {trade.flags.testOfExtreme.replace(/_/g, ' ')}
            </span>
          </Tip>
        )}
        {trade.flags?.pdInteraction && (
          <Tip text={TIPS.pdInteraction}>
            <span className="px-2 py-1 rounded-lg text-[10px] font-bold bg-purple-500/15 text-purple-300 border border-purple-500/25">
              🧲 {trade.flags.pdInteraction.replace(/_/g, ' ')}
            </span>
          </Tip>
        )}
        {trade.flags?.gapBarWith2HM && (
          <Tip text={TIPS.exhaustionFade}>
            <span className="px-2 py-1 rounded-lg text-[10px] font-bold bg-orange-500/15 text-orange-300 border border-orange-500/25">
              🔥 Exhaustion Fade (Gap Bar + 2HM)
            </span>
          </Tip>
        )}
        {!trade.flags?.withTrend && !trade.flags?.testOfExtreme && (
          <Tip text={TIPS.noTest}>
            <span className="px-2 py-1 rounded-lg text-[10px] font-bold bg-red-500/10 text-red-400/60 border border-red-500/15">
              ⚠ Reversal without Test of Extreme — Beginner Trap Risk
            </span>
          </Tip>
        )}
        {trade.flags?.trendlineIntact && !trade.flags?.withTrend && (
          <Tip text={TIPS.trendlineIntact}>
            <span className="px-2 py-1 rounded-lg text-[10px] font-bold bg-red-500/10 text-red-400/60 border border-red-500/15">
              ⚠ Trendline Intact — No Permission to Reverse
            </span>
          </Tip>
        )}
      </div>

      {decomp && (
        <div className="rounded-lg border border-slate-700/50 overflow-hidden">
          <div className="bg-slate-800/50 px-3 py-2 text-[10px] font-bold text-slate-400 uppercase tracking-wider">
            Brooks Score Decomposition
          </div>
          <div className="divide-y divide-slate-800/50">
            {components.map(({ key, label, tip }) => {
              const comp = decomp[key];
              if (!comp) return null;
              return (
                <div key={key} className="flex items-start gap-3 px-3 py-2">
                  <span className="text-sm w-5 flex-shrink-0">{statusIcon(comp.score)}</span>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <Tip text={tip}>
                        <span className="text-xs font-bold text-slate-300 cursor-help inline-flex items-center gap-1">{label} <span className="text-slate-600 text-[8px]">ⓘ</span></span>
                      </Tip>
                      <span className={`text-xs font-mono font-bold ${comp.score >= 7 ? 'text-emerald-400' : comp.score >= 4 ? 'text-amber-400' : 'text-red-400'}`}>
                        {comp.score}/10
                      </span>
                    </div>
                    {comp.reasons?.length > 0 && (
                      <ul className="mt-1 space-y-0.5">
                        {comp.reasons.map((r, i) => (
                          <li key={i} className="text-[10px] text-slate-500 leading-tight">• {r}</li>
                        ))}
                      </ul>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {(trade.thesis || trade.reality) && (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div className="rounded-lg border border-slate-700/30 bg-slate-800/30 p-3">
            <div className="text-[10px] font-bold text-blue-400 uppercase mb-1.5">📝 Thesis</div>
            <p className="text-[11px] text-slate-300 leading-relaxed">{trade.thesis || '—'}</p>
          </div>
          <div className="rounded-lg border border-slate-700/30 bg-slate-800/30 p-3">
            <div className="text-[10px] font-bold text-amber-400 uppercase mb-1.5">📊 Reality</div>
            <p className="text-[11px] text-slate-300 leading-relaxed">{trade.reality || '—'}</p>
          </div>
        </div>
      )}

      <div className="rounded-lg border border-slate-700/30 bg-slate-800/30 p-3">
        <div className="text-[10px] font-bold text-slate-500 uppercase mb-2">Target vs Heat Gauge</div>
        <div className="space-y-1.5">
          <div className="flex items-center gap-2">
            <span className="text-[9px] text-emerald-400 font-mono w-8">MFE</span>
            <div className="flex-1 h-3 bg-slate-900 rounded-full overflow-hidden">
              <div className="h-full bg-gradient-to-r from-emerald-600 to-emerald-400 rounded-full transition-all" style={{ width: `${Math.min((mfePct / maxPct) * 100, 100)}%` }} />
            </div>
            <span className="text-[9px] font-mono text-emerald-400 w-16 text-right">{(trade.metrics?.mfePoints || 0).toFixed(1)} pts</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-[9px] text-red-400 font-mono w-8">MAE</span>
            <div className="flex-1 h-3 bg-slate-900 rounded-full overflow-hidden">
              <div className="h-full bg-gradient-to-r from-red-600 to-red-400 rounded-full transition-all" style={{ width: `${Math.min((maePct / maxPct) * 100, 100)}%` }} />
            </div>
            <span className="text-[9px] font-mono text-red-400 w-16 text-right">{(trade.metrics?.maePoints || 0).toFixed(1)} pts</span>
          </div>
        </div>
        {trade.profitLeftOnTable > 0 && (
          <div className="mt-2 text-[10px] text-amber-400 font-mono">
            Profit left on table: {trade.profitLeftOnTable.toFixed(1)} pts · MAE as stop: {(trade.maeAsStopPct || 0).toFixed(1)}%
          </div>
        )}
        {/* Brooks Compliance v2 — Capture Ratio & R:R in modal */}
        <div className="mt-2 flex gap-4">
          {trade.captureRatio != null && (
            <div className="flex items-center gap-1.5">
              <span className="text-[9px] text-slate-500 uppercase">Capture</span>
              <span className={`text-[11px] font-mono font-bold ${
                trade.captureRatio >= 0.5 ? 'text-emerald-400' : trade.captureRatio >= 0.25 ? 'text-amber-400' : 'text-red-400'
              }`}>{(trade.captureRatio * 100).toFixed(0)}%</span>
            </div>
          )}
          {trade.rewardToRisk != null && trade.rewardToRisk > 0 && (
            <div className="flex items-center gap-1.5">
              <span className="text-[9px] text-slate-500 uppercase">R:R</span>
              <span className={`text-[11px] font-mono font-bold ${
                trade.rewardToRisk >= 2 ? 'text-emerald-400' : trade.rewardToRisk >= 1 ? 'text-amber-400' : 'text-red-400'
              }`}>{trade.rewardToRisk.toFixed(1)}:1</span>
            </div>
          )}
          {trade.flags?.vacuumVelocity > 0 && (
            <div className="flex items-center gap-1.5">
              <span className="text-[9px] text-slate-500 uppercase">V-Vel</span>
              <span className={`text-[11px] font-mono font-bold ${
                trade.flags.vacuumVelocity >= 7 ? 'text-red-400' : 'text-slate-400'
              }`}>{trade.flags.vacuumVelocity}/10</span>
            </div>
          )}
        </div>
      </div>

      {trade.analogy && (
        <div className="rounded-lg border border-amber-500/20 bg-amber-500/5 p-3">
          <div className="flex items-start gap-2">
            <span className="text-amber-500 mt-0.5">💡</span>
            <p className="text-[11px] text-slate-300 leading-relaxed italic">"{trade.analogy}"</p>
          </div>
        </div>
      )}
    </div>
  );
}

function TradeDetailModal({ trade, session, onClose, onPrev, onNext }) {
  const totalBars = session?.candles?.length || 0;
  const [replayIdx, setReplayIdx] = useState(totalBars > 0 ? totalBars - 1 : 0);
  const [showAnnotations, setShowAnnotations] = useState(false);

  useEffect(() => {
    if (totalBars > 0) setReplayIdx(totalBars - 1);
  }, [trade, totalBars]);

  useEffect(() => {
    const handler = (e) => {
      if (e.key === 'Escape') onClose();
      if (e.key === 'ArrowLeft' && e.target.tagName !== 'INPUT') onPrev?.();
      if (e.key === 'ArrowRight' && e.target.tagName !== 'INPUT') onNext?.();
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [onClose, onPrev, onNext]);

  if (!trade) return null;

  const isWin = trade.metrics?.pnl > 0;
  const isLong = trade.pair?.entry?.side === 'LONG';

  return (
    <div className="fixed inset-0 z-50 flex items-start justify-center overflow-y-auto" onClick={onClose}>
      <div className="fixed inset-0 bg-black/80 backdrop-blur-sm" />
      <div
        className="relative w-full max-w-6xl mx-4 my-8 bg-slate-900 rounded-2xl border border-slate-700/50 shadow-2xl"
        onClick={e => e.stopPropagation()}
      >
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-800">
          <div className="flex items-center gap-4 flex-wrap">
            <span className={`text-lg font-black font-mono ${isWin ? 'text-emerald-400' : 'text-red-400'}`}>
              Trade #{trade.pair?.tradeNum || trade.idx + 1}
            </span>
            <span className="text-sm text-slate-400 font-mono">{trade.pair?.entry?.symbol}</span>
            <span className={`px-2 py-0.5 rounded text-[10px] font-bold ${isLong ? 'bg-emerald-500/15 text-emerald-400' : 'bg-red-500/15 text-red-400'}`}>
              {isLong ? '▲ LONG' : '▼ SHORT'}
            </span>
            <span className={`font-mono font-bold text-lg ${isWin ? 'text-emerald-400' : 'text-red-400'}`}>
              {trade.metrics?.pnl > 0 ? '+' : ''}{trade.metrics?.pnl?.toFixed(0)}
            </span>
            <span className="text-xs text-slate-500 font-mono">{trade.pair?.entry?.dateTimeStr}</span>
          </div>
          <div className="flex items-center gap-2 flex-shrink-0">
            <button
              onClick={() => setShowAnnotations(a => !a)}
              className={`px-3 py-1.5 rounded-lg text-xs font-bold border transition-all ${
                showAnnotations
                  ? 'bg-amber-500/20 border-amber-500/30 text-amber-400'
                  : 'bg-slate-800 border-slate-700/50 text-slate-400 hover:text-slate-300'
              }`}
            >
              {showAnnotations ? '📐 ON' : '📐 Annotations'}
            </button>
            {onPrev && (
              <button onClick={onPrev} className="w-8 h-8 flex items-center justify-center rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-400 border border-slate-700/50 transition-colors">←</button>
            )}
            {onNext && (
              <button onClick={onNext} className="w-8 h-8 flex items-center justify-center rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-400 border border-slate-700/50 transition-colors">→</button>
            )}
            <button onClick={onClose} className="w-8 h-8 flex items-center justify-center rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-400 border border-slate-700/50 transition-colors">✕</button>
          </div>
        </div>

        <div className="px-6 py-4 border-b border-slate-800">
          {session ? (
            <>
              <div className="overflow-x-auto rounded-lg border border-slate-800">
                <SessionCandlestickChart
                  session={session}
                  trade={trade}
                  replayIdx={replayIdx < totalBars - 1 ? replayIdx : null}
                  showAnnotations={showAnnotations}
                />
              </div>
              {totalBars > 0 && (
                <div className="mt-3">
                  <BarByBarReplay
                    totalBars={totalBars}
                    replayIdx={replayIdx}
                    setReplayIdx={setReplayIdx}
                    session={session}
                  />
                </div>
              )}
            </>
          ) : (
            <div className="text-center py-10 text-slate-500">
              <span className="text-2xl block mb-2">📊</span>
              No session chart data available for this trade.
            </div>
          )}
        </div>

        <div className="px-6 py-4">
          <ScoreDecompositionPanel trade={trade} />
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// MAIN APP
// ─────────────────────────────────────────────────────────────────────────────
export default function App() {
  const csvTrades = useMemo(() => analyzeAllTrades(), []);
  const [enrichedTrades, setEnrichedTrades] = useState(null);
  const [dataSource, setDataSource] = useState('csv_only');
  const [enrichedMeta, setEnrichedMeta] = useState(null);
  const [sessions, setSessions] = useState(null);
  const [selectedTrade, setSelectedTrade] = useState(null);

  // Try to load enriched_trades.json on mount
  useEffect(() => {
    const baseUrl = import.meta.env.BASE_URL || '/';
    fetch(`${baseUrl}enriched_trades.json`)
      .then(res => {
        if (!res.ok) throw new Error('Not found');
        return res.json();
      })
      .then(data => {
        if (data && data.trades && data.trades.length > 0) {
          const converted = convertEnrichedToUIFormat(data.trades);
          setEnrichedTrades(converted);
          setDataSource(data.realDataTrades > 0 ? 'real' : 'csv_only');
          setEnrichedMeta(data);
          if (data.sessions) setSessions(data.sessions);
          console.log(`✅ Loaded enriched data: ${data.realDataTrades}/${data.totalTrades} trades with real chart data`);
        }
      })
      .catch(() => {
        console.log('ℹ️ No enriched_trades.json found — using CSV-only fallback');
      });
  }, []);

  const allTrades = enrichedTrades || csvTrades;
  const realCount = enrichedMeta ? enrichedMeta.realDataTrades : 0;

  const [filter, setFilter] = useState({
    outcome: 'ALL', date: 'ALL', symbol: 'ALL',
    barbWire: false, traps: false, stopRun: false,
    antiPortfolio: false, tradeQuality: 'ALL',
    tfo: false, m2bm2s: false, channelBreak: false, testOfExtreme: false,
  });

  const filtered = useMemo(() => {
    return allTrades.filter(t => {
      if (filter.antiPortfolio) {
        if (t.metrics.pnl > 0) return false;
        const score = t.score?.total ?? t.score ?? 0;
        if (score >= 6 && !t.flags.isBarbWire && !t.flags.isMiddleOfMiddle) return false;
      }
      if (filter.outcome === 'WINS' && t.metrics.pnl <= 0) return false;
      if (filter.outcome === 'LOSSES' && t.metrics.pnl >= 0) return false;
      if (filter.date !== 'ALL' && !t.pair.entry.dateTimeStr.startsWith(filter.date)) return false;
      if (filter.symbol !== 'ALL' && !t.pair.entry.symbol.startsWith(filter.symbol)) return false;
      if (filter.barbWire && !t.flags.isBarbWire) return false;
      if (filter.traps && !(t.flags.isFailedFailure || t.flags.isInstitutionalTrap)) return false;
      if (filter.stopRun && !t.flags.isStopRun) return false;
      if (filter.tradeQuality !== 'ALL' && t.tradeQuality !== filter.tradeQuality) return false;
      if (filter.tfo && !t.flags.isTFO) return false;
      if (filter.m2bm2s && !t.flags.isM2B && !t.flags.isM2S) return false;
      if (filter.channelBreak && !t.flags.channelLineBreak) return false;
      if (filter.testOfExtreme && !t.flags.testOfExtreme) return false;
      return true;
    });
  }, [allTrades, filter]);

  const selectedIdx = selectedTrade ? filtered.findIndex(t => t.idx === selectedTrade.idx) : -1;
  const handlePrevTrade = useCallback(() => {
    if (selectedIdx > 0) setSelectedTrade(filtered[selectedIdx - 1]);
  }, [selectedIdx, filtered]);
  const handleNextTrade = useCallback(() => {
    if (selectedIdx >= 0 && selectedIdx < filtered.length - 1) setSelectedTrade(filtered[selectedIdx + 1]);
  }, [selectedIdx, filtered]);

  return (
    <div className="min-h-screen bg-[#0a0a0f] text-slate-200">
      {/* Background grid */}
      <div className="fixed inset-0 bg-[linear-gradient(rgba(30,41,59,0.1)_1px,transparent_1px),linear-gradient(90deg,rgba(30,41,59,0.1)_1px,transparent_1px)] bg-[size:60px_60px] pointer-events-none" />

      <div className="relative max-w-[1400px] mx-auto px-6 py-8">
        <SummaryHeader trades={allTrades} />
        <DataSourceBanner dataSource={dataSource} realCount={realCount} totalCount={allTrades.length} />
        <PainHeatmap trades={allTrades} filter={filter} setFilter={setFilter} />
        <TradingIntelligence trades={allTrades} filter={filter} setFilter={setFilter} />
        {filter.antiPortfolio && <AntiPortfolioView trades={filtered} allTrades={allTrades} />}
        <FilterBar filter={filter} setFilter={setFilter} trades={allTrades} />

        {/* Trade Cards Grid */}
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
          {filtered.map((trade, i) => (
            <TradeCard key={`${trade.pair.entry.dateTimeStr}-${trade.idx}`} trade={trade} onSelect={setSelectedTrade} />
          ))}
        </div>

        {filtered.length === 0 && (
          <div className="flex flex-col items-center justify-center py-20 text-slate-500">
            <span className="text-4xl mb-3">🔍</span>
            <span className="text-sm">No trades match the current filters</span>
          </div>
        )}

        {/* Footer */}
        <div className="mt-12 text-center text-[10px] text-slate-700">
          Trade Integrity Dashboard · Al Brooks Price Action Framework · Built with React + Tailwind
        </div>
      </div>

      {selectedTrade && (
        <TradeDetailModal
          trade={selectedTrade}
          session={sessions ? sessions[selectedTrade.sessionKey] : null}
          onClose={() => setSelectedTrade(null)}
          onPrev={selectedIdx > 0 ? handlePrevTrade : null}
          onNext={selectedIdx < filtered.length - 1 ? handleNextTrade : null}
        />
      )}
    </div>
  );
}
